/**
 * @fileoverview Tooltip component — modular entry point.
 * @module module/Tooltip
 */

import { default as razyui } from '../../index.js';
import { TooltipDef as DEF } from '../Tooltip.def.js';

import { DEFAULTS, CLS, PART } from './constants.js';
import { createTooltipEl, positionTooltip } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';

const Tooltip = class {
    #root      = null;
    #destroyed = false;
    #config    = {};
    #eventAC   = null;
    #contentEl = null;
    #arrowEl   = null;
    #$content  = null;
    #timer     = null;
    #visible   = false;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Tooltip: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    #init() {
        const root = this.#root;
        root.addClass(CLS.ROOT);
        PART.ROOT.apply(root);

        const { contentEl, arrowEl, $content } = createTooltipEl(this.#config);
        this.#contentEl = contentEl;
        this.#arrowEl   = arrowEl;
        this.#$content  = $content;

        // ARIA: link trigger to tooltip
        root[0].setAttribute('aria-describedby', contentEl.id);

        const ac   = new AbortController();
        const opts = { signal: ac.signal };
        const el   = root[0];

        el.addEventListener('mouseenter', () => this.#scheduleShow(), opts);
        el.addEventListener('mouseleave', () => this.#scheduleHide(), opts);
        el.addEventListener('focusin',    () => this.#scheduleShow(), opts);
        el.addEventListener('focusout',   () => this.#scheduleHide(), opts);

        this.#eventAC = ac;
    }

    #scheduleShow() {
        clearTimeout(this.#timer);
        this.#timer = setTimeout(() => this.show(), this.#config.delay);
    }

    #scheduleHide() {
        clearTimeout(this.#timer);
        this.hide();
    }

    show() {
        if (this.#visible) return;
        this.#visible = true;

        // Append to body for measurement
        const contentEl = this.#contentEl;
        contentEl.style.position = 'absolute';
        contentEl.style.top = '0';
        contentEl.style.left = '0';
        document.body.appendChild(contentEl);

        // Acquire z-index from registry so tooltips stack above dialogs etc.
        zIndexRegistry.acquire(contentEl);

        // Position
        positionTooltip(
            this.#root[0],
            contentEl,
            this.#arrowEl,
            this.#config.placement,
            this.#config.offset,
        );

        // Show
        this.#$content.addClass(CLS.VISIBLE);
        emitEvent(this.#root[0], 'show');
    }

    hide() {
        if (!this.#visible) return;
        this.#visible = false;

        this.#$content.removeClass(CLS.VISIBLE);

        // Release z-index and remove after transition
        zIndexRegistry.release(this.#contentEl);
        setTimeout(() => {
            if (!this.#visible && this.#contentEl.parentNode) {
                this.#contentEl.parentNode.removeChild(this.#contentEl);
            }
        }, 200);

        emitEvent(this.#root[0], 'hide');
    }

    setText(text) {
        this.#config.text = text;
        // Update only the text node, not the arrow child
        const el = this.#contentEl;
        el.childNodes[0].textContent = text;
    }

    getControl() {
        const self = this;
        return {
            get text()       { return self.#config.text; },
            set text(v)      { self.setText(v); },
            get placement()  { return self.#config.placement; },
            set placement(v) { self.#config.placement = v; },
            get delay()      { return self.#config.delay; },
            set delay(v)     { self.#config.delay = Number(v); },
            show:    () => self.show(),
            hide:    () => self.hide(),
            setText: (t) => self.setText(t),
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        clearTimeout(this.#timer);
        this.hide();
        this.#eventAC?.abort();
        zIndexRegistry.release(this.#contentEl);
        if (this.#contentEl.parentNode) {
            this.#contentEl.parentNode.removeChild(this.#contentEl);
        }
    }
};

export default Tooltip;
