/**
 * @fileoverview Tooltip constants.
 * @module module/Tooltip/constants
 */
import { defineParts } from '../shared/definePart.js';


/** CSS class names */
export const CLS = Object.freeze({
    ROOT:    'tooltip',
    CONTENT: 'tooltip-content',
    ARROW:   'tooltip-arrow',
    VISIBLE: 'is-visible',
});

export const DEFAULTS = Object.freeze({
    text: '',
    placement: 'top',       // top | bottom | left | right
    delay: 200,
    offset: 8,
});

export const PART = defineParts('Tooltip', {
    ROOT        : { class: 'tooltip-trigger', aliases: ['root', 'trigger'] },
    CONTENT     : { class: 'tooltip-content', aliases: ['content', 'popup'] },
    ARROW       : { class: 'tooltip-arrow', aliases: ['arrow'] },
});

PART.ROOT.jit     = 'relative inline-block';
PART.CONTENT.jit  = 'absolute px-[var(--tt-px)] py-[var(--tt-py)] bg-[var(--tt-bg)] fg-[var(--tt-text)] text-[var(--tt-font-size)] rounded-[var(--tt-radius)] [white-space:nowrap] [pointer-events:none] opacity-0 [transition:opacity_.15s_ease,transform_.15s_ease] [transform:scale(0.95)] {is-visible}:opacity-100 {is-visible}:[transform:scale(1)] shadow-[var(--tt-shadow)]';
PART.ARROW.jit    = 'absolute w-[6px] h-[6px] bg-[var(--tt-bg)] [transform:rotate(45deg)]';