/**
 * @fileoverview Tooltip view — DOM setup and positioning.
 * @module module/Tooltip/view
 */

import { CLS, PART } from './constants.js';

/**
 * Build tooltip DOM (appended to body on show).
 */
export function createTooltipEl(config) {
    const tooltipId = 'rui-tip-' + Math.random().toString(36).slice(2, 8);
    const $content = PART.CONTENT.create({ id: tooltipId });
    $content.addClass(CLS.ROOT);
    $content.text(config.text).setAttr({ role: 'tooltip' });
    const contentEl = $content[0];

    const $arrow = PART.ARROW.create();
    $content.append($arrow);
    const arrowEl = $arrow[0];

    return { contentEl, arrowEl, $content, $arrow };
}

/**
 * Position the tooltip relative to trigger.
 */
export function positionTooltip(triggerEl, contentEl, arrowEl, placement, offset) {
    const rect = triggerEl.getBoundingClientRect();
    const tipRect = contentEl.getBoundingClientRect();
    const scrollX = window.scrollX;
    const scrollY = window.scrollY;

    let top, left, arrowTop, arrowLeft;

    switch (placement) {
        case 'top':
            top  = rect.top + scrollY - tipRect.height - offset;
            left = rect.left + scrollX + (rect.width - tipRect.width) / 2;
            arrowTop  = tipRect.height - 3;
            arrowLeft = tipRect.width / 2 - 3;
            break;
        case 'bottom':
            top  = rect.bottom + scrollY + offset;
            left = rect.left + scrollX + (rect.width - tipRect.width) / 2;
            arrowTop  = -3;
            arrowLeft = tipRect.width / 2 - 3;
            break;
        case 'left':
            top  = rect.top + scrollY + (rect.height - tipRect.height) / 2;
            left = rect.left + scrollX - tipRect.width - offset;
            arrowTop  = tipRect.height / 2 - 3;
            arrowLeft = tipRect.width - 3;
            break;
        case 'right':
            top  = rect.top + scrollY + (rect.height - tipRect.height) / 2;
            left = rect.right + scrollX + offset;
            arrowTop  = tipRect.height / 2 - 3;
            arrowLeft = -3;
            break;
    }

    contentEl.style.top  = `${top}px`;
    contentEl.style.left = `${left}px`;
    arrowEl.style.top  = `${arrowTop}px`;
    arrowEl.style.left = `${arrowLeft}px`;
}
